module binary_search (
    input wire [2:0] index,
    input wire write_enable,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);
    reg [7:0] unused_memory [7:0]; // 8 entries of 8-bit unused_memory

    initial begin
        unused_memory[0] = 8'h01;
        unused_memory[1] = 8'h02;
        unused_memory[2] = 8'h03;
        unused_memory[3] = 8'h04;
        unused_memory[4] = 8'h05;
        unused_memory[5] = 8'h06;
        unused_memory[6] = 8'h07;
        unused_memory[7] = 8'h08;
    end

    always @(*) begin
        if (write_enable) begin
            unused_memory[index] = data_in; // Write new data to unused_memory
            data_out = 8'bz; // Output is high impedance during write
        end else begin
            data_out = unused_memory[index]; // Read data from unused_memory
        end
    end
endmodule
